/** Button_Task(presses, shuffle100) — presses = OLA[594]; shuffle100 = CustomLists.Research[39]
 *  (the 100-entry permutation; caller supplies it, this file doesn't own that table — see
 *  gamedata-w7-research.mjs's header for where it lives). Returns a BUTTON_TASKS index. */
export function buttonTask(presses, shuffle100) {
  const p = Number(presses ?? 0);
  const slot = Math.round(p - 100 * Math.floor(p / 100));
  const raw = Number(shuffle100?.[slot] ?? 0);
  return Math.round(raw - BUTTON_TASKS.length * Math.floor(raw / BUTTON_TASKS.length));
}

/** Button_REQ(presses, shuffle100) — the current requirement's threshold value. */
export function buttonReq(presses, shuffle100) {
  const taskId = buttonTask(presses, shuffle100);
  const task = BUTTON_TASKS[taskId];
  if (!task) throw new Error(`Button_REQ: no BUTTON_TASKS[${taskId}]`);
  const p = Number(presses ?? 0);
  if (task.mode === "linear") return Math.ceil(task.threshold + p * task.coeff);
  if (task.mode === "step") return Math.ceil(task.threshold + p / task.coeff);
  return task.threshold * Math.pow(task.coeff, p);   // "exponent"
}
